SELECT ?player ?receptions WHERE {
  ?player wdt:P106 wd:Q2951264 .
  ?player wdt:P3912 ?receptions .
  FILTER (datatype(?receptions) = xsd:integer)
} ORDER BY DESC(?receptions) LIMIT 1

